#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 3e6+5;
const LD Pi = acos(-1.0);
struct Complex{LD x,y;};
LL n,m,lmi,lent,re[N];
Complex a[N],b[N];
Complex operator + (const Complex &A , const Complex &B){
    return {A.x+B.x,A.y+B.y};
}
Complex operator - (const Complex &A , const Complex &B){
    return {A.x-B.x,A.y-B.y};
}
Complex operator * (const Complex &A , const Complex &B){
    return {A.x*B.x-A.y*B.y,A.x*B.y+A.y*B.x};
}
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void FFT_iFFT(Complex *A,int Opt){
    //处理 FFT/IFFT 的核心函数
    //Opt 表示处理类型，1 表示 FFT、-1 表示 IFFT
    for(int i=0;i<lmi;i++)
        if(i<re[i])swap(A[i],A[re[i]]);
    //交换到迭代的位置
    for(int mid=1;mid<lmi;mid<<=1){
        //枚举区间半长
        Complex omega={cos(Pi/mid),Opt*sin(Pi/mid)};
        //利用欧拉公式算出单位根
        for(int R=(mid<<1),i=0;i<lmi;i+=R){
            Complex w={1,0};
            //用于求解单位根的高次方
            for(int k=0;k<mid;k++,w=w*omega){
                Complex t1=A[i+k],t2=w*A[i+mid+k];
                A[i+k]=t1+t2,A[i+mid+k]=t1-t2;
            }//对应变换
        }
    }
}
int main(){
    n=read(),m=read();
    lmi=1,lent=0;
    while(lmi<=n+m)lmi*=2,lent++;//算长度
    for(int i=0;i<=n;i++)a[i].x=read();
    for(int i=0;i<=m;i++)b[i].x=read();
    for(int i=0;i<lmi;i++)
        re[i]=(re[i>>1]>>1)|((i&1)<<(lent-1));
    //用二进制算出每个位置最终达到的位置
    FFT_iFFT(a,1);FFT_iFFT(b,1);
    //做两次 FFT 变为点值表示法
    for(int i=0;i<=lmi;i++)a[i]=a[i]*b[i];//乘
    FFT_iFFT(a,-1);
    //做 IFFT 换回系数表示法
    for(int i=0;i<=n+m;i++)
        cout<<(int)(round(a[i].x/lmi))<<" ";
    //输出！
    return 0;
}
